import { useEvent } from "../../hooks/use-event.js";
import { isRowSelected } from "./is-row-selected.js";
export function useRowsSelected(s, rowIdToRow, rowParents) {
    const rowsSelected = useEvent(() => {
        const rows = [];
        for (const node of rowIdToRow.values()) {
            const selected = isRowSelected(node.row.id, s.rowSelections, rowParents);
            if (selected)
                rows.push(node.row);
        }
        return { rows, state: s.rowSelectionsRaw };
    });
    return rowsSelected;
}
export function useRowSelectSplitLookup(s, leafs, group, rowParents) {
    const rowsSelected = useEvent(() => {
        const rows = [];
        for (const row of leafs.values()) {
            if (isRowSelected(row.id, s.rowSelections, rowParents))
                rows.push(row);
        }
        if (group) {
            for (const node of group.values()) {
                const row = node.row;
                const selected = isRowSelected(row.id, s.rowSelections, rowParents);
                if (selected)
                    rows.push(row);
            }
        }
        return { rows, state: s.rowSelectionsRaw };
    });
    return rowsSelected;
}
